import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import MediaShowcaseSwiper from '../components/MediaShowcaseSwiper';
import { mediaItems } from '../mediaData/media';
import api from '../services/api';

const Home = () => {
  const [mediaItems, setMediaItems] = useState([]);

  useEffect(() => {
    const fetchMedia = async () => {
      try {
        const { data } = await api.get('/media');
        if (!data) return;

        const mappedItems = data?.media?.map((item) => ({
          id: item._id,
          type: item.type,
          src: `http://localhost:5000${item.url}`,
          thumb: `http://localhost:5000${item.url}`,
          alt: item.filename,
          label: new Date(item.createdAt).toLocaleDateString('en-GB', { month: 'short', year: 'numeric' }),
          caption: item.filename.replace(/\.[^/.]+$/, '').replace(/-/g, ' '),
        }))

        setMediaItems(mappedItems);
      } catch (error) {
        console.error('Error fetching media:', error);
      }
    };
    fetchMedia();
  }, []);

  const heroVideo = mediaItems.find((item) => item.type === 'video');

  return (
    <div>
      <section className="hero" style={{ position: 'relative', overflow: 'hidden' }}>
        {heroVideo && (
          <video
            src={heroVideo.src}
            autoPlay
            loop
            muted
            playsInline
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              zIndex: 0,
            }}
          />
        )}
        <div
          style={{
            position: 'absolute',
            inset: 0,
            background: 'rgba(0,0,0,0.45)',
            zIndex: 1,
          }}
        />
        <div className="hero-content" style={{ position: 'relative', zIndex: 2 }}>
          <h1 className='text-5xl font-bold text-white'>Redefining Luxury</h1>
          <p className='text-yellow-300 text-2xl'>Discover the essentials of modern minimalism.</p>
          <Link to="/shop" className="btn">Explore Collection</Link>
        </div>
      </section>

      <div className="container">
        <h2 className="page-title">Featured Pieces</h2>
        {mediaItems?.length > 0 ? <MediaShowcaseSwiper items={mediaItems} /> : <p>No media found</p>}
      </div>
    </div>
  );
};

export default Home;
